//RJ TEMPLATE PERMISSIONS UPDATE
// STRY0074534 - write was only allowing the owner or the admin to write to a template.  
// Glboal designers should be able to update all global templates.
// OU designers should be able to update all OU templates
// Personal Templates should be checked against the owner
// Template Admin shouold be able to update any, apply the same permissiosn as read to the write.
var allow = false;

var UserPermissions  = new UserInfoScripts();
allow = UserPermissions.userHasProcessRights(current);

answer = allow;
